import collections
import math

def solution(limit: int = 1000) -> int:
    """
    Uses Euclid's formula to generate all primitive Pythagorean triples 
    up to the perimeter limit and their multiples.
    a = k(m^2 - n^2), b = k(2mn), c = k(m^2 + n^2), p = 2km(m + n)
    """
    counts = collections.Counter()
    m_limit = int(math.sqrt(limit / 2))

    for m in range(2, m_limit + 1):
        for n in range(1, m):
            if (m - n) % 2 == 1 and math.gcd(m, n) == 1:
                p_primitive = 2 * m * (m + n)
                for p in range(p_primitive, limit + 1, p_primitive):
                    counts[p] += 1

    return counts.most_common(1)[0][0]


if __name__ == "__main__":
    print(solution(1000))
